//! Smoke test proving `MockAscomConnectionBackend` (generated by
//! `mockall::automock` on the `AscomConnectionBackend` trait) can be
//! constructed, programmed with expectations, and observed by callers.
//!
//! This establishes the scaffolding for unit-testing per-device ASCOM
//! wrappers without a live Windows COM driver. Per-device modules
//! (camera, switch, cover_calibrator, …) are migrated to consume the
//! trait in a follow-on task; this file just verifies the mock works.
//!
//! The `mock` cargo feature is enabled for this test crate via
//! dev-dependencies in `ascom/Cargo.toml`, which is what surfaces
//! `MockAscomConnectionBackend`.

// Why cfg(windows): the trait and the connection wrapper live under
// `#[cfg(windows)]` in `nightshade_ascom`. On non-Windows targets the symbols
// do not exist, so the whole file is compiled to nothing.
#![cfg(windows)]

use mockall::predicate::eq;
use nightshade_ascom::{AscomConnectionBackend, MockAscomConnectionBackend};

#[test]
fn mock_backend_records_and_satisfies_expectations() {
    // Why: this is the minimum proof that mockall is correctly wired:
    //  1. `MockAscomConnectionBackend::new()` constructs an instance.
    //  2. `.expect_get_dispid()` and `.expect_call_method()` programme
    //     expected calls + return values keyed by argument matchers.
    //  3. Invoking the mock through the trait surface (so we exercise the
    //     trait dispatch, not the concrete `Mock…` inherent methods)
    //     returns the programmed values.
    //  4. On drop, mockall verifies the `.times(1)` expectations actually
    //     fired — if either is missed the test fails the harness check.
    let mut mock = MockAscomConnectionBackend::new();

    mock.expect_get_dispid()
        .with(eq("Connected"))
        .times(1)
        .returning(|_| Ok(0x1234));

    mock.expect_call_method()
        .with(eq("AbortExposure"))
        .times(1)
        .returning(|_| Ok(()));

    // Use the trait surface explicitly so a future migration of per-device
    // modules to `&dyn AscomConnectionBackend` would exercise the same path.
    let backend: &dyn AscomConnectionBackend = &mock;

    assert_eq!(backend.get_dispid("Connected"), Ok(0x1234));
    assert!(backend.call_method("AbortExposure").is_ok());
}

#[test]
fn mock_backend_propagates_errors_through_trait() {
    // Why: ensure error strings flow through the mock unchanged — important
    // because per-device wrappers will rely on the exact error format when
    // these tests are expanded to cover failure paths (e.g. HRESULT 0x80004005).
    let mut mock = MockAscomConnectionBackend::new();

    mock.expect_get_dispid()
        .with(eq("BogusProperty"))
        .times(1)
        .returning(|name| Err(format!("Failed to get DISPID for {}: E_NOTIMPL", name)));

    let backend: &dyn AscomConnectionBackend = &mock;

    let err = backend.get_dispid("BogusProperty").unwrap_err();
    assert!(
        err.contains("E_NOTIMPL"),
        "expected E_NOTIMPL in error: {err}"
    );
    assert!(
        err.contains("BogusProperty"),
        "expected name in error: {err}"
    );
}
